/** Capability toolkit threshold: legendary_t0 and above have capability_modifiers */
export function hasCapabilityToolkit(tier: Cycle13RarityTier): boolean {
  return ['legendary_t0', 'legendary_t0_5', 'legendary_t1', 'legendary_t2', 'set_t1', 'set_t2'].includes(tier);
}

/** T4 annotation threshold: legendary_t1 and above */
export function hasT4Annotation(tier: Cycle13RarityTier): boolean {
  return ['legendary_t1', 'legendary_t2', 'set_t1', 'set_t2'].includes(tier);
}

/** Derive human-readable display name from character_id */
export function deriveCharacterDisplayName(characterId: string): string {
  // e.g. "S1_endgame_str_01_heavy_barbarian" → "Heavy Barbarian"
  const parts = characterId.split('_');
  // Find the part after the 2-digit index (e.g., "01")
  const indexIdx = parts.findIndex((p) => /^\d{2}$/.test(p));
  if (indexIdx >= 0 && indexIdx < parts.length - 1) {
    return parts
      .slice(indexIdx + 1)
      .map((p) => p.charAt(0).toUpperCase() + p.slice(1))
      .join(' ');
  }
  return characterId;
}

